void swap(int *px, int *py) {
	int tmp;
	cout << "In swap() : *px = " << *px << ", *py = " << *py << endl;
	tmp = *px; *px = *py; *py = tmp;
	cout << "In swap() : *px = " << *px << ", *py = " << *py << endl;
}
