> 레퍼런스를 이용한 참조에 의한 호출

~~~C++
#include <iostream>
#include <windows.h>
using namespace std;

void swap(int &rx, int &ry);

int main() {
	int a = 100, b = 200;
	cout << "swap() 호출전: a = " << a << ", b = " << b << endl;
	swap(a, b);
	cout << "swap() 호출후: a = " << a << ", b = " << b << endl;

	system("pause");
}

void swap(int &rx, int &ry) {
	int tmp;
	tmp = rx; rx = ry; ry = tmp;
}
~~~
