void percentage(int *arr);

int main(){
    int count[N] = {42, 37, 83, 33};
    cout << "인원수 : ";
    print_arr(count);
    percentage(count);
    cout << "\n백분율 : ";
    print_arr(count);

    return 0;
}

void print_arr(int *arr){
    for(int i = 0; i < N; i++){
        cout << *(arr + i) << "\t";
    }
}
void percentage(int *arr){
    int sum = 0;
    for(int i = 0; i < N; i++){
        sum = sum + *(arr + i);
    }
    for(int i = 0; i < N; i++){
        *(arr + i) = *(arr + i) * 100 / sum;
    }
}
