#include <iostream>
#include <cstdlib>
#include <ctime>
using namespace std;

class EvenRandom{
public:
    EvenRandom();
    int next();
    int nextinRange(int low, int high);
};

int main(){
    EvenRandom r;
    cout << "-- 0에서 " << RAND_MAX << "까지의 랜덤 짝수 정수 10개 : " << endl;
    for(int i = 0; i < 10; i++){
        int n = r.next();
        cout << n << '\t';
    }
    cout << endl << endl << "-- 2에서 10까지의 랜덤 짝수 정수 10개 : " << endl;
    for(int i = 0; i < 10; i++){
        int n = r.nextinRange(2, 10);
        cout << n << '\t';
    }

    return 0;
}

EvenRandom::EvenRandom(){
    srand((unsigned int) time(0));
}

int EvenRandom::next(){
    int ran = rand();
    while(true){
        if(ran % 2 == 0){
            return ran;
        }
        ran = rand();
    }
}

int EvenRandom::nextinRange(int low, int high){
    int ran = rand() % (high - low + 1) + low;
    while(true){
        if(ran % 2 == 0){
            return ran;
        }
        ran = rand() % (high - low + 1) + low;
    }
}
