    ~MyintStack(){delete [] parr;}
};

int main(){
    MyintStack a(10);
    for(int i = 0; i < 11; i++){
        if(a.push(i))
            cout << i << '\t';
        else
            cout << endl << i + 1 << "번째 stack full" << endl;
    }
    int n;
    for(int i = 0; i < 11; i++){
        if(a.pop(n))
            cout << n << '\t';
        else
            cout << endl << i + 1 << "번째 stack empty" << endl;
    }

    return 0;
}

MyintStack::MyintStack(int size){
    tos = 0;
    parr = new int[size];
}
bool MyintStack::push(int n){
    if(tos == 10)
        return false;
    parr[tos] = n;
    tos++;
    return true;
}
bool MyintStack::pop(int &refn){
    if(tos == 0)
        return false;
    tos--;
    refn = parr[tos];
    return true;
}
