> stack.cpp

~~~C++
#include <iostream>
using namespace std;

class Stack{
    int size;
    int *mem;
    int tos;
public:
    Stack(int size = 4){
        this->size = size;
        mem = new int[size];
        tos = -1;
    }
    ~Stack(){delete [] mem;}
    Stack &operator<<(int n);
    Stack &operator>>(int &n);
    bool operator!();
};

int main(){
    Stack stack(10);
    stack << 1 << 2 << 3 << 4 << 5;
    while(true){
        if(!stack) break;
        int x;
        stack >> x;
        cout << x << '\t';
    }
    cout << endl;

    return 0;
}

Stack &Stack::operator<<(int n){
    if(tos == size - 1){
        return *this;
    }
    this->tos++;
    this->mem[tos] = n;
    return *this;
}
Stack &Stack::operator>>(int &n){
    if(tos == -1){
        return *this;
    }
    n = this->mem[tos];
    this->tos--;
    return *this;
}
bool Stack::operator!(){
    if(tos == -1)
        return true;
    else
        return false;
}
~~~

