> generic.cpp

~~~C++
#include <iostream>
using namespace std;

class Point{
    int x, y;
public:
    Point(int x = 0, int y = 0):x(x), y(y){}
    void show(){cout << '(' << x << ',' << y << ')' << endl;}
};

template<class T>
class MyStack{
    int tos;
    T data[100];
public:
    MyStack();
    void push(T element);
    T pop();
};

int main(){
    MyStack<int *> ipStack;
    int *p = new int[3];
    for(int i = 0; i < 3; i++)
        p[i] = i * 10;
    ipStack.push(p);
    int *q = ipStack.pop();
    for(int i = 0; i < 3; i++)
        cout << q[i] << '\t';
    cout << endl;
    delete [] p;

    MyStack<Point> pointStack;
    Point a(2, 3), b;
    pointStack.push(a);
    b = pointStack.pop();
    b.show();

    MyStack<Point *> pStack;
    pStack.push(new Point(10, 20));
    Point *pPoint = pStack.pop();
    pPoint->show();

    MyStack<string> stringStack;
    string s = "C++";
    stringStack.push(s);
    stringStack.push("Zerohertz");
    cout << stringStack.pop() << '\t';
    cout << stringStack.pop() << endl;

    return 0;
}

template<class T>
MyStack<T>::MyStack(){
    tos = -1;
}
template<class T>
void MyStack<T>::push(T element){
    if(tos == 99){
        cout << "Stack full" << endl;
        return;
    }
    tos++;
    data[tos] = element;
}
template<class T>
T MyStack<T>::pop(){
    T Data;
    if(tos == -1){
        cout << "Stack empty" << endl;
        return 0;
    }
    Data = data[tos--];
    return Data;
}
