# Low-pass filter

> Moving Average function 사용

~~~C++
#define WinSize 100
float data[WinSize];
int i = 0;

void setup() {
  Serial.begin(9600);
}

void loop() {
  int a = 0;
  float sol = 0;
  float val = analogRead(A0);
  val = (val*5/1023)*1000-2420;
  val = abs(val);
  a = i % WinSize;
  data[a] = val;
  if(i > WinSize ){
    for(int j = 0; j < WinSize ; j++){
      sol = sol + data[j] / WinSize;
    }
  }
  Serial.println(sol);
  delay(10);
  i++;
}
~~~

