    int64 t1, t2;
    bool do_flip = false;

    while (1) {
        cam.grab();
        cam.retrieve(frame);

        if (do_flip)
            flip(frame, frame, -1);
         t1 = getTickCount();

        cvtColor(frame, gray, cv::COLOR_BGR2GRAY);
        resize(gray, reduced, Size(0, 0), 0.5, 0.5);

        vector<Rect> faces;
        cascade.detectMultiScale(reduced, faces, 1.1, 3, 0, Size(40, 40));

        for (size_t i = 0; i < faces.size(); i++) {
