# ConvertString2Float()

+ 문자열을 슬라이싱한 후에 `atof()`를 사용하여 전환해준다

> IMU_SensorView.cpp

~~~C++
void CIMUSensorView::convert2Float(char* data, float& roll, float& pitch)
{
	char data1[64] = {};
	char data2[64] = {};
	int flag = 0;
	int a = 0;
	int b = 0;
	while (1)
	{
		if (flag == 2)
			break;

		if (flag == 1)
		{
			data2[b] = data[a];
			if (data[a] == '\n')
			{
				flag = 2;
			}
			b++;
		}

		if (flag == 0)
		{
			data1[a] = data[a];
			if (data[a] == '\t')
			{
				flag = 1;
			}
		}
		a++;
	}
	float d1 = atof(data1);
	float d2 = atof(data2);

	roll = -d1 * PI / 180.0;
	pitch = d2 * PI / 180.0;
}
