	Identity.M[1][0] = 0; Identity.M[1][1] = 1; Identity.M[1][2] = 0;
	Identity.M[2][0] = 0; Identity.M[2][1] = 0; Identity.M[2][2] = 1;

	float theta4Prime = D[2] * D[2] + D[4] * D[4] - shoulderToWrist.SizeSquared();
	theta4Prime = theta4Prime / (2.0 * D[2] * D[4]);
