using namespace std;
using namespace cv; 
typedef struct {
	unsigned char r;
	unsigned char g;
	unsigned char b;
} Color;
typedef struct PosList {
	int x;
	int y;
	struct PosList *next;
} PosList;
int colordiff(Color a, Color b)
{	int dr, dg, db;
	dr = (int)((a.r < b.r) ? (b.r - a.r) : (a.r - b.r));
	dg = (int)((a.g < b.g) ? (b.g - a.g) : (a.g - b.g));
	db = (int)((a.b < b.b) ? (b.b - a.b) : (a.b - b.b));
	return dr + dg + db;
}PosList* newnode(int x, int y)
{	PosList *pos;
	pos = (PosList *)malloc(sizeof(PosList));
	pos->x = x;
	pos->y = y;
	pos->next = NULL;
	return pos;
}void delnode(PosList **pos)
{	free(*pos);
	*pos = NULL;
}void pl_push(PosList **list, PosList *pos)
{	pos->next = *list;
	*list = pos;
}PosList* pl_pop(PosList **list)
{	PosList *pos;
	pos = *list;
	*list = (*list)->next;
	return pos;
}void dellist(PosList **list)
{	PosList *a, *b;
	a = *list;
	while (a != NULL) {
		b = a->next;
		delnode(&a);
		a = b;
	}
}int contains(PosList *list, int x, int y)
{	while (list != NULL) {
		if (list->x == x && list->y == y)
			return 1;
		list = list->next;
	}
	return 0;
}void rgrow(IplImage *source, IplImage *dest, Color color, int threshold)
{	PosList *list_n;
	PosList *node_r;
	PosList *list_r;
	Color curcolor;
	int x, y;
	int sx, sy;
