		l[1]=0;
		l[0]=(l[1]-b0)/b1;
	}
	if(l[1]>=imageHeight)
	{
		l[1]=imageHeight;
		l[0]=(l[1]-b0)/b1;
	}
		l[2] = imageWidth; l[3] = b0 + b1*l[2];
	if(l[3]<=0)
	{
		l[3]=0;
		l[2]=(l[3]-b0)/b1;
	}
	if(l[3]>=imageHeight)
	{
		l[3]=imageHeight;
		l[2]=(l[3]-b0)/b1;
	}
