# Solution

~~~python
import sys

def convert_func(rot, s1, s2, idx_i_1, idx_j_1, idx_i_2, idx_j_2, i, j):
    if rot == 0:
        ni, nj = i + idx_i_1 - s1, j + idx_j_1 - s2
    elif rot == 1:
        ni, nj = -j + idx_i_2 + s1, i + idx_j_1 - s2
    elif rot == 2:
        ni, nj = -i + idx_i_2 + s1, -j + idx_j_2 + s2
    elif rot == 3:
        ni, nj = j + idx_i_1 - s1, -i + idx_j_2 + s2
    return ni, nj

def match(rot, key, M, lock, N, s1, s2, idx_i, idx_j, idx_i_1, idx_j_1, idx_i_2, idx_j_2):
    for i in range(M):
        for j in range(M):
            ni, nj = convert_func(rot, s1, s2, idx_i_1, idx_j_1, idx_i_2, idx_j_2, i, j)
            if (0 <= ni < N) and (0 <= nj < N):
                if (idx_i_1 <= ni <= idx_i_2) and (idx_j_1 <= nj <= idx_j_2):
                    if key[i][j] == lock[ni][nj]:
                        return False
                    else:
                        continue
                else:
                    if key[i][j] == 1:
                        return False
                    else:
                        continue
            else:
                continue
    return True

def solution(key, lock):
    keyRange = [[], []]
    N, M = len(lock), len(key)
    idx_i_1, idx_j_1, idx_i_2, idx_j_2 = sys.maxsize, sys.maxsize, 0, 0
    for i in range(N):
        for j in range(N):
            if lock[i][j] == 0:
                idx_i_1 = min(idx_i_1, i)
                idx_j_1 = min(idx_j_1, j)
                idx_i_2 = max(idx_i_2, i)
                idx_j_2 = max(idx_j_2, j)
    if idx_i_1 == sys.maxsize:
        return True
    idx_i, idx_j = idx_i_2 - idx_i_1, idx_j_2 - idx_j_1
    if idx_i + 1 > M or idx_j + 1 > M:
        return False
    for rot in range(4):
        for s1 in range(M - idx_i):
            for s2 in range(M - idx_j):
                if match(rot, key, M, lock, N, s1, s2, idx_i, idx_j, idx_i_1, idx_j_1, idx_i_2, idx_j_2):
                    return True
    return False
~~~

# 풀이

> [Programmers 92344: 파괴되지 않은 건물](https://school.programmers.co.kr/learn/courses/30/lessons/92344)

Brute-force 알고리즘을 적용하면 `250,000 * 1,000 * 1,000`의 시간 복잡도를 가지기 때문에 효율성 테스트를 통과할 수 없다.
따라서 `skill`의 행 길이가 최대 250,000이므로 해당 부분을 해결하는 것이 문제의 포인트다. (`board`의 각 원소를 필연적으로 수정 및 조회해야하기 때문)
아마도 시간 복잡도를 `250,000 + 1,000 * 1,000`으로 감쇠시킬 수 있는 알고리즘을 개발해야할 것이다.
최종적으로 구간 합을 이용해 풀 수 있었다.

<!-- More -->

---

# Solution

~~~python
def solution(board, skill):
    answer = 0
    convert = {1: -1, 2: 1}
    N, M = len(board), len(board[0])
    cum = [[0 for _ in range(M + 1)] for _ in range(N + 1)]
    for typ, r1, c1, r2, c2, degree in skill:
        cum[r1][c1] += convert[typ] * degree
        cum[r1][c2 + 1] -= convert[typ] * degree
        cum[r2 + 1][c1] -= convert[typ] * degree
        cum[r2 + 1][c2 + 1] += convert[typ] * degree
    for i in range(N + 1):
        for j in range(1, M + 1):
            cum[i][j] += cum[i][j - 1]
    for i in range(1, N + 1):
        for j in range(M + 1):
            cum[i][j] += cum[i - 1][j]
    for i in range(N):
        for j in range(M):
            if 0 < board[i][j] + cum[i][j]:
                answer += 1
    return answer
~~~

