def solution(board, skill):
    answer = 0
    convert = {1: -1, 2: 1}
    for s in skill:
        for i in range(s[1], s[3] + 1):
            for j in range(s[2], s[4] + 1):
                board[i][j] += convert[s[0]] * s[5]
    for i in board:
