~~~python
def solution(board, skill):
    answer = 0
    convert = {1: -1, 2: 1}
    tar = []
    for s in skill:
        for i in range(s[1], s[3] + 1):
            for j in range(s[2], s[4] + 1):
                board[i][j] += convert[s[0]] * s[5]
                if board[i][j] <= 0 and not (i, j) in tar:
                    tar.append((i, j))
                elif board[i][j] > 0 and (i, j) in tar:
                    tar.remove((i, j))
    answer = len(board) * len(board[0]) - len(tar)
    return answer
~~~

